// Unit 21 — Le Gérondif
// Gerund and present participle

export default {n:21,lang:"fr",srcLang:"en",track:"v2",title:"Le Gérondif",sub:"Gerund and present participle",icon:"🔄",level:"B1.5",color:"#7B5EE8",lessons:[
  {id:"fre21l1",title:"Le Participe Présent",icon:"📝",xp:15,board:true,steps:[
        {type:"intro",title:"Le Participe Présent",desc:"Learn how to form the present participle in French: take the nous form of the present tense, remove -ons, and add -ant. This is the foundation for the gérondif.",goals:["Form present participles from the nous stem","Learn the three irregular present participles","Recognize the -ant ending pattern"]},
        {type:"teach",trg:"mangeant",src:"eating (present participle)",pos:"noun",gender:null,phonetic:"mon-ZHON",note:"manger: nous mangeons, remove -ons, add -ant.\nThe e is kept to preserve the soft g sound.",example:"A: Comment on forme le participe présent de manger?\nB: On prend mangeons et on remplace -ons par -ant.\nA: Donc mangeant?\nB: Exactement! Le e reste pour garder le son zh.",exampleSrc:"A: How do you form the present participle of manger?\nB: You take mangeons and replace -ons with -ant.\nA: So mangeant?\nB: Exactly! The e stays to keep the zh sound.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"parlant",src:"speaking (present participle)",pos:"verb",gender:null,phonetic:"par-LON",note:"parler: nous parlons, remove -ons = parl + ant.\nRegular -er verbs follow this pattern consistently.",example:"A: Et pour le verbe parler?\nB: Nous parlons, donc parlant.\nA: C'est facile pour les verbes en -er!\nB: Oui, le schéma est toujours le même.",exampleSrc:"A: And for the verb parler?\nB: Nous parlons, so parlant.\nA: It's easy for -er verbs!\nB: Yes, the pattern is always the same.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"finissant",src:"finishing (present participle)",pos:"verb",gender:null,phonetic:"fee-nee-SON",note:"finir: nous finissons, remove -ons = finiss + ant.\nThe -iss- pattern appears in all -ir verb participles.",example:"A: Comment on fait le participe de finir?\nB: Nous finissons, donc finissant.\nA: Le double s reste?\nB: Oui, on garde tout le radical: finiss + ant.",exampleSrc:"A: How do you make the participle of finir?\nB: Nous finissons, so finissant.\nA: The double s stays?\nB: Yes, you keep the whole stem: finiss + ant.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"prenant",src:"taking (present participle)",pos:"verb",gender:null,phonetic:"pruh-NON",note:"prendre: nous prenons, remove -ons = pren + ant.\nMost irregular verbs still follow the nous stem rule.",example:"A: Et prendre? C'est régulier?\nB: Nous prenons, donc prenant.\nA: Pas de surprises?\nB: Non, même les verbes irréguliers suivent la règle du nous.",exampleSrc:"A: And prendre? Is it regular?\nB: Nous prenons, so prenant.\nA: No surprises?\nB: No, even irregular verbs follow the nous rule.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"tip",title:"Forming the Present Participle",deepDive:"The present participle is invariable as a verb form: it never agrees in gender or number. However, when used as an adjective, it follows normal adjective agreement rules. We will explore this difference in a later lesson.",text:"Take the NOUS form of the present tense.\nRemove -ons. Add -ant.\n\nExamples:\nnous parlons → parlant (speaking)\nnous finissons → finissant (finishing)\nnous mangeons → mangeant (eating)\nnous prenons → prenant (taking)\nnous faisons → faisant (doing)\nnous vendons → vendant (selling)\n\nOnly THREE exceptions:\nêtre → étant (being)\navoir → ayant (having)\nsavoir → sachant (knowing)"},
        {type:"mc",q:"What is the present participle of choisir (nous choisissons)?",opts:["choisissant","choisant","choissant","choisirant"],ans:"choisissant",hint:"Remove the ending from the nous form and add the participle suffix."},
        {type:"teach",trg:"faisant",src:"doing / making (present participle)",pos:"noun",gender:null,phonetic:"fuh-ZON",note:"faire: nous faisons → faisant.\nPronunciation: the ai sounds like uh, not eh.",example:"A: Le participe présent de faire?\nB: C'est faisant, de nous faisons.\nA: La prononciation change un peu, non?\nB: Oui, on dit fuh-ZON, pas feh-ZON.",exampleSrc:"A: The present participle of faire?\nB: It's faisant, from nous faisons.\nA: The pronunciation changes a bit, right?\nB: Yes, you say fuh-ZON, not feh-ZON.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"étant",src:"being (present participle, irregular)",pos:"noun",gender:null,phonetic:"eh-TON",note:"être → étant (NOT êtant or étions + ant).\nOne of only three irregular present participles.",example:"A: Être a un participe présent régulier?\nB: Non, c'est étant. C'est irrégulier.\nA: Comme avoir et savoir?\nB: Exactement. Ce sont les trois exceptions.",exampleSrc:"A: Does être have a regular present participle?\nB: No, it's étant. It's irregular.\nA: Like avoir and savoir?\nB: Exactly. Those are the three exceptions.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"ayant",src:"having (present participle, irregular)",pos:"noun",gender:null,phonetic:"eh-YON",note:"avoir → ayant (NOT avons + ant).\nUsed in compound forms: ayant fini = having finished.",example:"A: Et le participe présent de avoir?\nB: C'est ayant. Aussi irrégulier.\nA: C'est logique, avoir est souvent irrégulier.\nB: Oui, ayant est très utile dans les constructions composées.",exampleSrc:"A: And the present participle of avoir?\nB: It's ayant. Also irregular.\nA: That makes sense, avoir is often irregular.\nB: Yes, ayant is very useful in compound constructions.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"sachant",src:"knowing (present participle, irregular)",pos:"noun",gender:null,phonetic:"sah-SHON",note:"savoir → sachant (NOT savant).\nSavant means scholar/learned (adjective/noun).",example:"A: Savoir aussi est irrégulier?\nB: Oui, c'est sachant, pas savant.\nA: Savant existe pourtant?\nB: Oui, mais savant est un nom ou adjectif, pas le participe.",exampleSrc:"A: Savoir is also irregular?\nB: Yes, it's sachant, not savant.\nA: But savant exists though?\nB: Yes, but savant is a noun or adjective, not the participle.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"Which is the correct present participle of vendre (nous vendons)?",opts:["vendant","vendrant","vendont","vendissant"],ans:"vendant",hint:"Remove the nous ending and add the standard participle suffix."},
        {type:"fb",opts:["lisant","lirant","lisont","luant"],hint:"Take the stem from the nous form and attach the participle ending.",s:"Le participe présent de lire (nous lisons) est {1}.",a:["lisant"]},
        {type:"match",pairs:[{trg:"parlant",src:"speaking"},{trg:"finissant",src:"finishing"},{trg:"faisant",src:"doing"},{trg:"ayant",src:"having"},{trg:"sachant",src:"knowing"}]},
        {type:"mc",q:"Why is the present participle of manger 'mangeant' and not 'mangant'?",opts:["The e keeps the soft g sound before a","Manger is an irregular verb","All -er verbs keep the e","It is a spelling error that stuck"],ans:"The e keeps the soft g sound before a",hint:"Without the extra vowel, the consonant would change its pronunciation."},
        {type:"fb",opts:["étant","êtant","essant","éant"],hint:"This is one of three verbs that does not follow the nous stem rule.",s:"Le participe présent irrégulier de être est {1}.",a:["étant"]},
        {type:"drag_fill",hint:"These three verbs do not derive from the nous present tense form.",s:"Les trois participes irréguliers sont {1}, {2} et {3}.",blanks:{"1":"étant","2":"ayant","3":"sachant"},pool:["étant","ayant","sachant","faisant","prenant","allant"]},
        {type:"mc",q:"What is the present participle of boire (nous buvons)?",opts:["buvant","boivant","buant","boirant"],ans:"buvant",hint:"Start from the nous stem and apply the standard formation rule."},
        {type:"fb",opts:["écrivant","écrirant","écrivent","écriant"],hint:"The stem from nous écrivons minus the ending gives you the base.",s:"Nous écrivons → le participe présent est {1}.",a:["écrivant"]}
  ]},
  {id:"fre21l2",title:"En + Participe Présent",icon:"🔄",xp:15,board:true,steps:[
        {type:"intro",title:"En + Participe Présent",desc:"Discover le gérondif: the construction en + present participle. This powerful structure expresses simultaneous actions, manner, and cause.",goals:["Form the gérondif with en + present participle","Understand that en never changes","Recognize the gérondif in context"]},
        {type:"teach",trg:"en mangeant",src:"while eating / by eating",pos:"intj",gender:null,phonetic:"on mon-ZHON",note:"En + present participle = the gérondif.\nEn never changes. Always en, never aux or dans.",example:"A: Qu'est-ce que tu fais pendant le déjeuner?\nB: Je lis en mangeant.\nA: Ce n'est pas facile!\nB: On s'habitue avec le temps.",exampleSrc:"A: What do you do during lunch?\nB: I read while eating.\nA: That's not easy!\nB: You get used to it over time.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"en parlant",src:"while speaking / by speaking",pos:"verb",gender:null,phonetic:"on par-LON",note:"En parlant = by speaking, while speaking.\nThe gérondif always refers to the subject of the main verb.",example:"A: Comment améliorer son français?\nB: On progresse en parlant tous les jours.\nA: Avec qui?\nB: Avec des amis, des collègues, tout le monde!",exampleSrc:"A: How to improve your French?\nB: You improve by speaking every day.\nA: With whom?\nB: With friends, colleagues, everyone!",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"en faisant",src:"while doing / by doing",pos:"intj",gender:null,phonetic:"on fuh-ZON",note:"En faisant = by doing, while doing.\nVery common in everyday French conversation.",example:"A: Tu as trouvé la solution?\nB: Oui, en faisant des recherches sur Internet.\nA: Ça t'a pris combien de temps?\nB: En faisant attention, j'ai trouvé en dix minutes.",exampleSrc:"A: Did you find the solution?\nB: Yes, by doing research on the Internet.\nA: How long did it take you?\nB: By being careful, I found it in ten minutes.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"en écoutant",src:"while listening / by listening",pos:"intj",gender:null,phonetic:"on eh-koo-TON",note:"En écoutant = by/while listening.\nNo elision: always en écoutant, never en n'écoutant.",example:"A: Comment tu apprends le français?\nB: J'apprends en écoutant des podcasts.\nA: Tu comprends tout?\nB: Pas tout, mais en écoutant souvent, ça s'améliore.",exampleSrc:"A: How do you learn French?\nB: I learn by listening to podcasts.\nA: Do you understand everything?\nB: Not everything, but by listening often, it improves.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"tip",title:"Le Gérondif: en + participe présent",deepDive:"The gérondif exists only with en. Without en, you have a simple present participle, which has different uses (we will see those in lesson 6). The gérondif is one of the most useful constructions in French for connecting two simultaneous actions concisely.",text:"Formation: en + present participle (invariable)\n\nen parlant = while/by speaking\nen mangeant = while/by eating\nen faisant = while/by doing\nen écoutant = while/by listening\n\nKey rules:\n1. En NEVER changes (no agreement)\n2. The gérondif ALWAYS refers to the SUBJECT of the main verb\n3. The subject of both actions MUST be the same person\n\nCorrect: Il chante en travaillant. (He sings while working.)\nWrong: Il chante en Marie travaillant. (Different subjects!)"},
        {type:"mc",q:"Which correctly forms the gérondif of marcher?",opts:["en marchant","en marcher","en marchons","en marché"],ans:"en marchant",hint:"Combine the preposition with the present participle form of the verb."},
        {type:"teach",trg:"en lisant",src:"while reading / by reading",pos:"intj",gender:null,phonetic:"on lee-ZON",note:"En lisant = by/while reading.\nLire: nous lisons → lisant → en lisant.",example:"A: Tu as découvert ce livre comment?\nB: En lisant un article dans le journal.\nA: Et tu l'as aimé?\nB: Oui, j'ai appris beaucoup en lisant ce livre.",exampleSrc:"A: How did you discover this book?\nB: By reading an article in the newspaper.\nA: And did you like it?\nB: Yes, I learned a lot by reading this book.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"fb",opts:["en","dans","aux","avec"],hint:"Only one small word introduces the gérondif construction.",s:"Elle chante {1} cuisinant.",a:["en"]},
        {type:"mc",q:"'J'ai appris le français en regardant des films.' What does en regardant express?",opts:["The means by which the person learned","A command to watch films","That watching happened after learning","That someone else was watching"],ans:"The means by which the person learned",hint:"The construction describes how the main action was accomplished."},
        {type:"teach",trg:"en souriant",src:"while smiling / smilingly",pos:"intj",gender:null,phonetic:"on soo-ree-ON",note:"En souriant = while smiling, with a smile.\nDescribes the manner of the main action.",example:"A: Comment elle a réagi à la nouvelle?\nB: Elle a accepté en souriant.\nA: Elle était contente alors?\nB: Oui, elle a dit merci en souriant.",exampleSrc:"A: How did she react to the news?\nB: She accepted while smiling.\nA: She was happy then?\nB: Yes, she said thank you with a smile.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"fb",opts:["envoyant","envoyer","envoyé","envoie"],hint:"The gérondif needs the participle form, not the infinitive or past form.",s:"Il a trouvé un emploi en {1} des candidatures en ligne.",a:["envoyant"]},
        {type:"mc",q:"Why is 'Il chante en Marie dansant' incorrect?",opts:["The subject of both actions must be the same","Marie cannot dance","En must come before Marie","Dansant is not a real word"],ans:"The subject of both actions must be the same",hint:"The gérondif always refers back to the person performing the main verb."},
        {type:"match",pairs:[
          {trg:"en parlant",src:"by/while speaking"},
          {trg:"en écoutant",src:"by/while listening"},
          {trg:"en faisant",src:"by/while doing"},
          {trg:"en lisant",src:"by/while reading"},
          {trg:"en souriant",src:"while smiling"}
        ]},
        {type:"drag_fill",hint:"The gérondif uses the preposition plus the participle form.",s:"Nous avons résolu le problème {1} {2} ensemble.",blanks:{"1":"en","2":"travaillant"},pool:["en","travaillant","travailler","avec","travaillé","de"]},
        {type:"mc",q:"'Elle s'est blessée en courant.' What happened?",opts:["She hurt herself while running","She ran to the hospital","Running made her feel better","She was running beautifully"],ans:"She hurt herself while running",hint:"The gérondif tells you what ___ was doing when the injury occurred."},
        {type:"fb",opts:["faisant","faire","fait","faisait"],hint:"After en, the verb must be in the present participle form.",s:"On apprend beaucoup en {1} des erreurs.",a:["faisant"]},
        {type:"mc",q:"Which sentence uses the gérondif correctly?",opts:["Il écoute de la musique en conduisant","Il écoute de la musique en conduit","Il écoute de la musique en conduire","Il écoute de la musique en a conduit"],ans:"Il écoute de la musique en conduisant",hint:"After en, the verb needs the specific form ending in the participle suffix."}
  ]},
  {id:"fre21l3",title:"Actions Simultanées",icon:"⏱️",xp:15,board:true,steps:[
        {type:"intro",title:"Actions Simultanées",desc:"Use the gérondif to describe two actions happening at the same time. The gérondif action is secondary, providing context for the main action.",goals:["Express simultaneous actions with the gérondif","Identify main vs secondary actions","Use the gérondif for everyday multi-tasking descriptions"]},
        {type:"teach",trg:"Il lit en mangeant",src:"He reads while eating",pos:"verb",gender:null,phonetic:"eel LEE on mon-ZHON",note:"Two simultaneous actions: reading (main) + eating (secondary).\nThe gérondif describes the background action.",example:"A: Marc fait quoi à midi?\nB: Il lit en mangeant son sandwich.\nA: Il arrive à se concentrer?\nB: Oui, il lit toujours en mangeant.",exampleSrc:"A: What does Marc do at noon?\nB: He reads while eating his sandwich.\nA: Can he concentrate?\nB: Yes, he always reads while eating.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Elle téléphone en marchant",src:"She talks on the phone while walking",pos:"verb",gender:null,phonetic:"el teh-leh-FON on mar-SHON",note:"The gérondif shows what happens alongside the main action.\nBoth actions share the same subject: elle.",example:"A: Où est Sophie?\nB: Elle téléphone en marchant dans le parc.\nA: Elle fait toujours ça?\nB: Oui, elle marche toujours en téléphonant.",exampleSrc:"A: Where is Sophie?\nB: She's on the phone while walking in the park.\nA: Does she always do that?\nB: Yes, she always walks while making calls.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Les enfants chantent en jouant",src:"The children sing while playing",pos:"noun",gender:"pl",phonetic:"leh zon-FON SHONT on zhoo-ON",note:"The gérondif works with any subject: il, elle, nous, ils.\nThe form of the participle never changes.",example:"A: Les enfants sont dans le jardin?\nB: Oui, ils chantent en jouant.\nA: Ils ont l'air heureux!\nB: Toujours! Ils rient en jouant ensemble.",exampleSrc:"A: Are the children in the garden?\nB: Yes, they're singing while playing.\nA: They look happy!\nB: Always! They laugh while playing together.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"Je regarde les nouvelles en prenant mon café",src:"I watch the news while having my coffee",pos:"verb",gender:null,phonetic:"zhuh ruh-GARD leh noo-VEL on pruh-NON mon kah-FEH",note:"Everyday routine described with the gérondif.\nEn prenant = while having/taking.",example:"A: Qu'est-ce que tu fais le matin?\nB: Je regarde les nouvelles en prenant mon café.\nA: Tu regardes la télé ou ton téléphone?\nB: Mon téléphone, en prenant mon petit déjeuner.",exampleSrc:"A: What do you do in the morning?\nB: I watch the news while having my coffee.\nA: Do you watch TV or your phone?\nB: My phone, while having breakfast.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Il écoute un podcast en courant.' Which action is the main action?",opts:["Running is the main activity","Listening is the main activity","Both are equally main","Neither is the main activity"],ans:"Listening is the main activity",hint:"The action in the ___ clause, before the gérondif, carries the primary focus."},
        {type:"tip",title:"Simultaneous Actions",deepDive:"In English, you can say 'Walking, he noticed a cat' with a dangling participle. In French, the gérondif MUST share the subject of the main verb. If the subjects differ, you need a subordinate clause: Pendant que Marie chantait, Pierre dansait.",text:"The gérondif expresses what happens AT THE SAME TIME as the main action.\n\nStructure: Main action + en + present participle\n\nIl travaille en écoutant de la musique.\n(main: working, secondary: listening)\n\nElle conduit en chantant.\n(main: driving, secondary: singing)\n\nNous discutons en marchant.\n(main: discussing, secondary: walking)\n\nThe gérondif action is the BACKGROUND.\nThe main verb carries the FOCUS."},
        {type:"fb",opts:["marchant","marcher","marchons","marché"],hint:"The background action needs the present participle after en.",s:"Nous parlons de nos vacances en {1} dans le parc.",a:["marchant"]},
        {type:"teach",trg:"Il s'est endormi en regardant la télé",src:"He fell asleep while watching TV",pos:"verb",gender:null,phonetic:"eel seh ton-dor-MEE on ruh-gar-DON lah teh-LEH",note:"Past tense main verb + gérondif.\nThe gérondif itself does not change tense.",example:"A: Pierre est où?\nB: Il s'est endormi en regardant la télé.\nA: Encore? Il fait ça souvent?\nB: Oui, il s'endort toujours en regardant un film.",exampleSrc:"A: Where's Pierre?\nB: He fell asleep while watching TV.\nA: Again? Does he do that often?\nB: Yes, he always falls asleep while watching a movie.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Elle a ri en lisant le message.' What happened?",opts:["She laughed while reading the message","She read after laughing","She laughed instead of reading","She stopped reading to laugh"],ans:"She laughed while reading the message",hint:"The gérondif describes what was happening when the main action took place."},
        {type:"fb",opts:["écoutant","écouter","écouté","écoutent"],hint:"The secondary action of listening needs the participle form after en.",s:"Les étudiants prennent des notes en {1} le professeur.",a:["écoutant"]},
        {type:"match",pairs:[
          {trg:"Il lit en mangeant",src:"He reads while eating"},
          {trg:"Elle chante en cuisinant",src:"She sings while cooking"},
          {trg:"Nous rions en parlant",src:"We laugh while talking"},
          {trg:"Il s'endort en lisant",src:"He falls asleep while reading"}
        ]},
        {type:"mc",q:"Which sentence correctly uses the gérondif for simultaneous actions?",opts:["Je réfléchis en me promenant","Je réfléchis en me promener","Je réfléchis en me promenais","Je réfléchis en me promené"],ans:"Je réfléchis en me promenant",hint:"The reflexive verb keeps its pronoun, and the verb itself takes the participle form."},
        {type:"drag_fill",hint:"The two-word gérondif construction describes the background activity.",s:"Mon frère écoute de la musique {1} {2} ses devoirs.",blanks:{"1":"en","2":"faisant"},pool:["en","faisant","faire","pendant","fait","de"]},
        {type:"fb",opts:["conduisant","conduire","conduit","conduisait"],hint:"Driving requires the present participle form after the preposition.",s:"Tu ne devrais pas téléphoner en {1}.",a:["conduisant"]},
        {type:"mc",q:"'Ils discutent en attendant le bus.' How many subjects are there?",opts:["One subject (ils) for both actions","Two subjects, one for each action","Three subjects total","No clear subject"],ans:"One subject (ils) for both actions",hint:"The gérondif construction requires ___ ___ to belong to the same person or group."},
        {type:"drag_fill",hint:"The gérondif tells how the discovery happened.",s:"Elle a découvert la réponse {1} {2} le livre.",blanks:{"1":"en","2":"lisant"},pool:["en","lisant","lire","dans","lu","par"]},
        {type:"mc",q:"Choose the correct translation: 'We talk while walking.'",opts:["Nous parlons en marchant","Nous parlons en marcher","Nous marchons en parlant","Nous en marchant parlons"],ans:"Nous parlons en marchant",hint:"The main action is talking, and the gérondif describes the secondary activity."}
  ]},
  {id:"fre21l4",title:"Manière et Cause",icon:"🎯",xp:15,board:true,steps:[
        {type:"intro",title:"Manière et Cause",desc:"The gérondif expresses not just simultaneous action, but also HOW something is done (manner) and WHY something happened (cause).",goals:["Use the gérondif to express manner (how)","Use the gérondif to express cause (why)","Distinguish manner from cause meanings"]},
        {type:"teach",trg:"J'ai appris en pratiquant",src:"I learned by practicing",pos:"intj",gender:null,phonetic:"zheh ah-PREE on prah-tee-KON",note:"En pratiquant = by practicing (manner).\nAnswers the question: How did you learn?",example:"A: Comment tu as appris à cuisiner?\nB: J'ai appris en pratiquant tous les jours.\nA: Tu as suivi des cours?\nB: Non, j'ai tout appris en pratiquant seul.",exampleSrc:"A: How did you learn to cook?\nB: I learned by practicing every day.\nA: Did you take classes?\nB: No, I learned everything by practicing alone.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Elle a réussi en travaillant dur",src:"She succeeded by working hard",pos:"verb",gender:null,phonetic:"el ah reh-oo-SEE on trah-vah-YON DOOR",note:"En travaillant = by working (manner/means).\nDescribes HOW success was achieved.",example:"A: Comment Marie a eu cette promotion?\nB: Elle a réussi en travaillant dur.\nA: Elle mérite son succès.\nB: Oui, on réussit toujours en travaillant.",exampleSrc:"A: How did Marie get that promotion?\nB: She succeeded by working hard.\nA: She deserves her success.\nB: Yes, you always succeed by working hard.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"Il a gagné de l'argent en vendant sa voiture",src:"He earned money by selling his car",pos:"verb",gender:null,phonetic:"eel ah gah-NYEH duh lar-ZHON on von-DON sah vwah-TOOR",note:"En vendant = by selling (manner/means).\nShows the METHOD used to achieve a result.",example:"A: Comment Pierre a pu payer son voyage?\nB: Il a gagné de l'argent en vendant sa voiture.\nA: C'était une bonne idée?\nB: Oui, il a résolu son problème en vendant.",exampleSrc:"A: How could Pierre pay for his trip?\nB: He earned money by selling his car.\nA: Was it a good idea?\nB: Yes, he solved his problem by selling.",funFact:"A -re verb, the smallest of the three regular verb groups."},
        {type:"teach",trg:"En courant, il est tombé",src:"While running, he fell (cause)",pos:"intj",gender:null,phonetic:"on koo-RON eel eh tom-BEH",note:"En courant = because of/while running (cause).\nThe gérondif explains WHY the fall happened.",example:"A: Qu'est-ce qui est arrivé à Thomas?\nB: En courant, il est tombé dans l'escalier.\nA: Il s'est fait mal?\nB: Oui, en tombant il s'est tordu la cheville.",exampleSrc:"A: What happened to Thomas?\nB: While running, he fell on the stairs.\nA: Did he hurt himself?\nB: Yes, while falling he twisted his ankle.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"tip",title:"Manner vs Cause",deepDive:"When the gérondif is at the beginning of the sentence, it often emphasizes cause. When it comes after the main verb, it more often expresses manner or simultaneity. But context always determines the meaning.",text:"MANNER (how?): answers Comment?\nJ'ai appris en pratiquant. (How? By practicing.)\nElle a maigri en faisant du sport. (How? By exercising.)\n\nCAUSE (why?): answers Pourquoi?\nEn courant, il est tombé. (Why? Because he was running.)\nEn mangeant trop vite, j'ai eu mal. (Why? Because I ate too fast.)\n\nContext decides the meaning:\nIl a trouvé un emploi en cherchant en ligne.\n= He found a job BY searching online. (manner)\n\nEn glissant sur la glace, elle s'est cassé le bras.\n= She broke her arm BY slipping on ice. (cause)"},
        {type:"mc",q:"'Elle a maigri en faisant du sport.' What does en faisant express here?",opts:["The method she used to lose weight","A simultaneous unrelated action","A cause of weight gain","A future plan"],ans:"The method she used to lose weight",hint:"The gérondif answers the question of how the result was achieved."},
        {type:"teach",trg:"On économise en achetant en solde",src:"You save money by buying on sale",pos:"intj",gender:null,phonetic:"on eh-ko-no-MEEZ on ash-TON on SOLD",note:"En achetant = by buying (manner/means).\nPractical tip expressed with the gérondif.",example:"A: Comment tu fais pour économiser?\nB: On économise en achetant en solde.\nA: Tu attends toujours les soldes?\nB: Oui, on dépense moins en achetant malin.",exampleSrc:"A: How do you manage to save money?\nB: You save by buying on sale.\nA: Do you always wait for sales?\nB: Yes, you spend less by shopping smart.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"fb",opts:["regardant","regarder","regardé","regarde"],hint:"The method of improvement requires the present participle after en.",s:"Il a amélioré son français en {1} des films.",a:["regardant"]},
        {type:"mc",q:"'En traversant la rue, il a vu un accident.' What does en traversant express?",opts:["When/while crossing the street (cause/time)","After crossing the street","Before crossing the street","Instead of crossing the street"],ans:"When/while crossing the street (cause/time)",hint:"The gérondif at the start provides the context for when the main event occurred."},
        {type:"teach",trg:"En étudiant régulièrement, tu progresseras",src:"By studying regularly, you will progress",pos:"intj",gender:null,phonetic:"on eh-too-DYON reh-goo-LYEHR-mon too pro-greh-suh-RAH",note:"En étudiant = by studying (manner/means).\nGérondif can pair with any tense in the main clause.",example:"A: Je n'arrive pas à apprendre cette langue.\nB: En étudiant régulièrement, tu progresseras.\nA: Combien de temps par jour?\nB: En consacrant trente minutes par jour, ça suffit.",exampleSrc:"A: I can't manage to learn this language.\nB: By studying regularly, you will progress.\nA: How much time per day?\nB: By dedicating thirty minutes a day, that's enough.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"fb",opts:["En","Dans","Par","Avec"],hint:"The gérondif always begins with the same small word before the participle.",s:"{1} cherchant bien, tu trouveras la solution.",a:["En"]},
        {type:"mc",q:"'En mangeant trop vite, j'ai eu mal au ventre.' Is this manner or cause?",opts:["Cause: eating fast caused the stomachache","Manner: how he ate at the table","Simultaneous: two parallel actions","Contrast: despite eating fast"],ans:"Cause: eating fast caused the stomachache",hint:"The gérondif explains the reason for the negative result in the main clause."},
        {type:"match",pairs:[
          {trg:"J'ai appris en pratiquant",src:"Manner: by practicing"},
          {trg:"En courant, il est tombé",src:"Cause: fell because of running"},
          {trg:"Elle chante en cuisinant",src:"Simultaneous: sings while cooking"},
          {trg:"Il a réussi en travaillant",src:"Manner: by working hard"}
        ]},
        {type:"drag_fill",hint:"The gérondif describes the method used to find the apartment.",s:"Elle a trouvé un appartement {1} {2} des annonces en ligne.",blanks:{"1":"en","2":"consultant"},pool:["en","consultant","consulter","par","consulté","avec"]},
        {type:"fb",opts:["buvant","boire","bu","boit"],hint:"After en, the verb boire takes its present participle form from nous buvons.",s:"En {1} trop de café, il ne dort pas bien.",a:["buvant"]},
        {type:"mc",q:"Which sentence uses the gérondif to express cause?",opts:["En glissant sur le verglas, elle s'est blessée","Il téléphone en marchant","Elle sourit en parlant","Nous mangeons en regardant la télé"],ans:"En glissant sur le verglas, elle s'est blessée",hint:"Look for the sentence where the gérondif explains why something bad happened."},
        {type:"drag_fill",hint:"The method of improvement uses the gérondif construction.",s:"Tu peux améliorer ta prononciation {1} {2} à voix haute.",blanks:{"1":"en","2":"lisant"},pool:["en","lisant","lire","par","lu","avec"]},
        {type:"mc",q:"'On apprend en faisant des erreurs.' The gérondif here expresses:",opts:["The means by which we learn","A warning not to make errors","That learning and errors happen separately","That errors prevent learning"],ans:"The means by which we learn",hint:"The construction describes HOW the ___ing process works."}
  ]},
  {id:"fre21l5",title:"Tout en + Gérondif",icon:"⚡",xp:15,board:true,steps:[
        {type:"intro",title:"Tout en + Gérondif",desc:"Discover tout en + present participle, which adds emphasis or expresses contrast and concession. Tout en suggests the two actions are surprising or contradictory.",goals:["Use tout en + gérondif for emphasis","Express contrast with tout en","Distinguish tout en from simple en"]},
        {type:"teach",trg:"Tout en souriant, elle pleurait",src:"While smiling, she was crying (contrast)",pos:"intj",gender:null,phonetic:"too ton soo-ree-ON el pluh-REH",note:"Tout en + gérondif = even while, despite doing.\nHighlights the contrast between two simultaneous actions.",example:"A: Comment a réagi Julie?\nB: Tout en souriant, elle pleurait.\nA: Les deux en même temps?\nB: Oui, elle souriait tout en ayant les larmes aux yeux.",exampleSrc:"A: How did Julie react?\nB: While smiling, she was crying.\nA: Both at the same time?\nB: Yes, she smiled while having tears in her eyes.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Tout en étant fatigué, il a continué",src:"Even though he was tired, he continued",pos:"intj",gender:null,phonetic:"too ton eh-TON fah-tee-GEH eel ah kon-tee-NOO-EH",note:"Tout en étant = despite being, even though being.\nExpresses concession: the action continues regardless.",example:"A: Pierre a fini le marathon?\nB: Oui, tout en étant fatigué, il a continué.\nA: Quelle détermination!\nB: Il a couru tout en souffrant beaucoup.",exampleSrc:"A: Did Pierre finish the marathon?\nB: Yes, even though he was tired, he continued.\nA: What determination!\nB: He ran despite suffering a lot.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"Elle travaille tout en écoutant de la musique",src:"She works while also listening to music",pos:"verb",gender:null,phonetic:"el trah-VAHY too ton eh-koo-TON duh lah moo-ZEEK",note:"Tout en adds emphasis: she REALLY does both at once.\nStronger than simple en écoutant.",example:"A: Marie peut se concentrer avec de la musique?\nB: Oui, elle travaille tout en écoutant de la musique.\nA: Moi, je ne pourrais pas!\nB: Elle fait tout en écoutant quelque chose.",exampleSrc:"A: Can Marie concentrate with music?\nB: Yes, she works while also listening to music.\nA: I couldn't do that!\nB: She does everything while listening to something.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"tip",title:"Tout en vs Simple en",deepDive:"Tout in this construction is an adverb modifying en + gérondif. It is invariable (never toute, toutes). Even with a feminine subject: Elle sourit tout en pleurant (NOT toute en pleurant). This is different from tout as an adjective, which does agree.",text:"Simple en + gérondif: neutral simultaneous action\nIl mange en lisant. (He eats while reading.)\n\nTout en + gérondif: emphasis, contrast, or surprise\nTout en mangeant, il travaillait. (He was working EVEN WHILE eating.)\n\nContrast/Concession:\nTout en souriant, elle pleurait. (Despite smiling, she cried.)\nTout en étant malade, il est venu. (Despite being sick, he came.)\n\nEmphasis:\nElle parle tout en cuisinant. (She talks AND cooks at the same time!)\n\nTout en often implies the speaker finds the combination noteworthy or surprising."},
        {type:"mc",q:"What does tout en add to the gérondif?",opts:["Emphasis or contrast between the two actions","A negative meaning","A past tense meaning","A question form"],ans:"Emphasis or contrast between the two actions",hint:"The extra word before en signals that the combination is noteworthy or surprising."},
        {type:"teach",trg:"Il parle tout en sachant qu'il a tort",src:"He speaks despite knowing he is wrong",pos:"verb",gender:null,phonetic:"eel PARL too ton sah-SHON keel ah TOR",note:"Tout en sachant = despite knowing.\nClear concession: he speaks EVEN THOUGH he knows better.",example:"A: Pourquoi Marc continue de parler?\nB: Il parle tout en sachant qu'il a tort.\nA: C'est agaçant!\nB: Oui, il insiste tout en connaissant la vérité.",exampleSrc:"A: Why does Marc keep talking?\nB: He speaks despite knowing he's wrong.\nA: That's annoying!\nB: Yes, he insists despite knowing the truth.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"fb",opts:["Tout","Toute","En","Tous"],hint:"This invariable word adds emphasis or contrast before en. It never agrees.",s:"{1} en étant malade, elle est venue travailler.",a:["Tout"]},
        {type:"mc",q:"'Tout en comprenant le problème, il n'a rien fait.' What does this mean?",opts:["Despite understanding the problem, he did nothing","While understanding the problem, he fixed it","He did not understand the problem","He understood and then acted"],ans:"Despite understanding the problem, he did nothing",hint:"The construction expresses a contradiction between ___ and inaction."},
        {type:"teach",trg:"Elle sourit tout en ayant peur",src:"She smiles despite being afraid",pos:"verb",gender:null,phonetic:"el soo-REE too ton eh-YON PUR",note:"Tout en ayant = despite having/being.\nThe irregular participle ayant works with tout en.",example:"A: Sarah n'a pas l'air effrayée.\nB: Mais si, elle sourit tout en ayant peur.\nA: Elle cache bien ses émotions.\nB: Oui, elle reste calme tout en tremblant à l'intérieur.",exampleSrc:"A: Sarah doesn't look scared.\nB: But she is. She smiles despite being afraid.\nA: She hides her emotions well.\nB: Yes, she stays calm despite trembling inside.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"fb",opts:["sachant","savoir","su","sait"],hint:"After tout en, use the irregular participle of savoir.",s:"Il continue de fumer tout en {1} que c'est dangereux.",a:["sachant"]},
        {type:"mc",q:"'Elle rit tout en pleurant.' This suggests:",opts:["Both actions happen together, which is surprising","She laughed first, then cried","She chose laughing over crying","Laughing caused her to cry"],ans:"Both actions happen together, which is surprising",hint:"The tout en construction highlights that these two contradictory ___ coexist."},
        {type:"match",pairs:[
          {trg:"tout en souriant",src:"despite smiling / while smiling"},
          {trg:"tout en sachant",src:"despite knowing"},
          {trg:"tout en étant fatigué",src:"despite being tired"},
          {trg:"tout en travaillant",src:"while also working"}
        ]},
        {type:"drag_fill",hint:"The three-word construction emphasizes doing both actions simultaneously.",s:"Il mange {1} {2} {3} la télévision.",blanks:{"1":"tout","2":"en","3":"regardant"},pool:["tout","en","regardant","par","regarder","toute"]},
        {type:"mc",q:"Is tout in 'tout en marchant' variable (changes for feminine/plural)?",opts:["No, tout is invariable in this construction","Yes, it becomes toute for feminine","Yes, it becomes tous for plural","Yes, it becomes toutes for feminine plural"],ans:"No, tout is invariable in this construction",hint:"In this specific adverbial use, the word never changes regardless of the subject."},
        {type:"fb",opts:["étant","être","été","est"],hint:"The irregular participle of the verb to be follows tout en.",s:"Tout en {1} d'accord avec toi, je pense qu'on devrait attendre.",a:["étant"]},
        {type:"drag_fill",hint:"Despite being very busy: three-word construction with the irregular participle.",s:"{1} {2} {3} très occupée, elle trouve le temps de faire du sport.",blanks:{"1":"Tout","2":"en","3":"étant"},pool:["Tout","en","étant","Toute","de","être"]},
        {type:"mc",q:"Which sentence expresses the strongest contrast?",opts:["Tout en souriant, elle cachait sa tristesse","Elle souriait en marchant","Il parlait en mangeant","Nous travaillions en écoutant la radio"],ans:"Tout en souriant, elle cachait sa tristesse",hint:"Look for the sentence where the two actions seem contradictory."}
  ]},
  {id:"fre21l6",title:"Participe Présent: Adjectif vs Verbal",icon:"🔍",xp:15,board:true,steps:[
        {type:"intro",title:"Participe Présent: Adjectif vs Verbal",desc:"The present participle can be verbal (invariable, describes an action) or adjectival (agrees in gender and number, describes a quality). Learn to distinguish them.",goals:["Identify verbal present participles (invariable)","Identify adjectival present participles (agree)","Apply agreement rules correctly"]},
        {type:"teach",trg:"une histoire intéressante",src:"an interesting story",pos:"noun",gender:"f",phonetic:"oon ees-TWAHR an-teh-reh-SONT",note:"Intéressante = adjective (agrees with feminine histoire).\nDescribes a QUALITY of the story, not an action.",example:"A: Tu as lu ce livre?\nB: Oui, c'est une histoire intéressante.\nA: Intéressante comment?\nB: Les personnages sont fascinants et l'intrigue est surprenante.",exampleSrc:"A: Did you read this book?\nB: Yes, it's an interesting story.\nA: Interesting how?\nB: The characters are fascinating and the plot is surprising.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"une personne intéressant tout le monde",src:"a person interesting everyone",pos:"verb",gender:null,phonetic:"oon pehr-SON an-teh-reh-SON too luh MOND",note:"Intéressant = verbal participle (invariable, no agreement).\nIt has a direct object (tout le monde) = verb action.",example:"A: Qui est ce conférencier?\nB: C'est une personne intéressant tout le monde.\nA: Intéressant ne prend pas de e ici?\nB: Non, parce que c'est un verbe, pas un adjectif.",exampleSrc:"A: Who is that speaker?\nB: It's a person who interests everyone.\nA: Intéressant doesn't take an e here?\nB: No, because it's a verb, not an adjective.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"tip",title:"Adjective vs Verbal Participle",deepDive:"Some participles have different spellings as adjectives vs verbs. Key pairs: fatigant (verb) vs fatiguant (adj is actually fatigant too in modern French, but: provoquant (verb) vs provocant (adj), communiquant (verb) vs communicant (adj). These spelling differences are rare but exist in formal writing.",text:"ADJECTIVE (agrees in gender/number):\n- Describes a quality or characteristic\n- Can be replaced by another adjective\n- une femme charmante (a charming woman)\n- des films passionnants (exciting films)\n- des résultats surprenants (surprising results)\n\nVERBAL (invariable, no agreement):\n- Describes an action in progress\n- Often has a complement (object, adverb)\n- une femme charmant ses collègues (a woman charming her colleagues)\n- des enfants courant dans le parc (children running in the park)\n\nTest: Can you replace it with qui + conjugated verb?\nIf yes, it is VERBAL and does NOT agree."},
        {type:"teach",trg:"des enfants obéissants",src:"obedient children",pos:"noun",gender:"pl",phonetic:"deh zon-FON oh-beh-ee-SON",note:"Obéissants = adjective (agrees with plural enfants).\nDescribes their character, not a specific action.",example:"A: Comment sont tes enfants?\nB: Ce sont des enfants obéissants.\nA: Tu as de la chance!\nB: Oui, ils sont très obéissants et respectueux.",exampleSrc:"A: How are your children?\nB: They are obedient children.\nA: You are lucky!\nB: Yes, they are very obedient and respectful.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"les enfants obéissant à leurs parents",src:"the children obeying their parents",pos:"verb",gender:null,phonetic:"leh zon-FON oh-beh-ee-SON ah lur pah-RON",note:"Obéissant = verbal participle (invariable, no -s).\nIt has a complement: à leurs parents = action in progress.",example:"A: Les enfants écoutent bien?\nB: Oui, les enfants obéissant à leurs parents reçoivent une récompense.\nA: C'est une bonne motivation!\nB: Les enfants obéissant rapidement sont récompensés en premier.",exampleSrc:"A: Do the children listen well?\nB: Yes, the children obeying their parents receive a reward.\nA: That's good motivation!\nB: The children obeying quickly are rewarded first.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"mc",q:"'Des résultats surprenants' vs 'des résultats surprenant les chercheurs'. Why does the second not agree?",opts:["It has a direct object, making it a verb form","It is a spelling error","Surprenant never agrees","Plurals never need agreement"],ans:"It has a direct object, making it a verb form",hint:"When the participle per___s an action on something, it functions as a ___."},
        {type:"teach",trg:"une rue passante",src:"a busy street",pos:"noun",gender:"f",phonetic:"oon ROO pah-SONT",note:"Passante = adjective (agrees with feminine rue).\nDescribes a permanent quality of the street.",example:"A: C'est calme ce quartier?\nB: Non, c'est une rue passante.\nA: Il y a beaucoup de voitures?\nB: Oui, c'est une zone très passante le matin.",exampleSrc:"A: Is this neighborhood quiet?\nB: No, it's a busy street.\nA: Are there many cars?\nB: Yes, it's a very busy area in the morning.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"fb",opts:["fascinante","fascinant","fascinants","fascinantes"],hint:"As an adjective modifying a feminine singular noun, it needs agreement.",s:"C'est une histoire {1}. (fascinating, adjective, feminine)",a:["fascinante"]},
        {type:"mc",q:"'Les voyageurs descendant du train' uses the participle as:",opts:["A verbal form (invariable, describes an action)","An adjective (agrees with voyageurs)","A noun (the descenders)","A gérondif (with en)"],ans:"A verbal form (invariable, describes an action)",hint:"The participle ___ an ___ being per___ed, not a permanent quality."},
        {type:"fb",opts:["surprenantes","surprenant","surprenante","surprenants"],hint:"Feminine plural agreement is needed for this adjective modifying les remarques.",s:"Les remarques {1} du directeur ont surpris tout le monde. (surprising, adjective)",a:["surprenantes"]},
        {type:"match",pairs:[
          {trg:"une femme charmante",src:"adjective: a charming woman"},
          {trg:"une femme charmant ses amis",src:"verbal: a woman charming her friends"},
          {trg:"des films passionnants",src:"adjective: exciting films"},
          {trg:"des acteurs passionnant le public",src:"verbal: actors thrilling the audience"}
        ]},
        {type:"mc",q:"How do you know 'brillant' is an adjective in 'un étudiant brillant'?",opts:["It describes a quality with no complement or object","It ends in -ant","It comes after a noun","It is masculine"],ans:"It describes a quality with no complement or object",hint:"Without an action ___, the participle ___ a characteristic."},
        {type:"drag_fill",hint:"As a verbal participle with a location complement, it does not agree.",s:"Les employés {1} au bureau sont restés tard. (working, verbal)",blanks:{"1":"travaillant"},pool:["travaillant","travaillants","travaillante","travailler"]},
        {type:"fb",opts:["fatigant","fatiguant","fatigante","fatigants"],hint:"As an adjective modifying a masculine singular noun, no agreement changes are needed.",s:"C'est un spectacle {1}. (tiring, adjective, masculine)",a:["fatigant"]},
        {type:"mc",q:"'Les eaux courantes' vs 'les eaux courant vers la mer'. In which is courant an adjective?",opts:["Les eaux courantes (describes a type of water)","Les eaux courant vers la mer (describes flowing)","Both are adjectives","Neither is an adjective"],ans:"Les eaux courantes (describes a type of water)",hint:"The version with agreement and no complement ___ a permanent quality."},
        {type:"drag_fill",hint:"Both function as adjectives here and must agree with their nouns.",s:"C'est une personne très {1} et des résultats {2}. (charming, surprising)",blanks:{"1":"charmante","2":"surprenants"},pool:["charmante","surprenants","charmant","surprenant","charmantes","surprenantes"]},
        {type:"mc",q:"Which test helps determine if a participle is verbal or adjectival?",opts:["Replace it with qui + conjugated verb: if possible, it is verbal","Check if it ends in -ant: if so, it is always verbal","Count the syllables: fewer means adjective","Check if the subject is human: if so, it is verbal"],ans:"Replace it with qui + conjugated verb: if possible, it is verbal",hint:"If the participle can be restated as a relative clause with an active ___, it describes an action."}
  ]},
  {id:"fre21l7",title:"Constructions Avancées",icon:"🏗️",xp:15,board:true,steps:[
        {type:"intro",title:"Constructions Avancées",desc:"Go beyond the gérondif: learn après avoir/être + past participle, sans + infinitive, and avant de + infinitive for sequencing actions precisely.",goals:["Use après avoir/être + past participle for completed actions","Use sans + infinitive for without doing","Use avant de + infinitive for before doing"]},
        {type:"teach",trg:"après avoir mangé",src:"after having eaten / after eating",pos:"verb",gender:null,phonetic:"ah-PREH ah-VWAHR mon-ZHEH",note:"Après + avoir + past participle.\nFor actions completed BEFORE the main verb.\nThe subject of both clauses must be the same.",example:"A: Qu'est-ce que tu fais après le dîner?\nB: Après avoir mangé, je me promène.\nA: C'est une bonne habitude!\nB: Oui, après avoir mangé, je digère mieux en marchant.",exampleSrc:"A: What do you do after dinner?\nB: After eating, I take a walk.\nA: That's a good habit!\nB: Yes, after eating, I digest better by walking.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"après être arrivé",src:"after having arrived / after arriving",pos:"verb",gender:null,phonetic:"ah-PREH ETR ah-ree-VEH",note:"Après + être + past participle (for être verbs).\nThe participle agrees with the subject: arrivé/arrivée.",example:"A: Qu'est-ce que tu as fait en arrivant?\nB: Après être arrivé, j'ai téléphoné à ma mère.\nA: Elle était contente?\nB: Oui, après être arrivé sain et sauf, elle était rassurée.",exampleSrc:"A: What did you do when you arrived?\nB: After arriving, I called my mother.\nA: Was she happy?\nB: Yes, after arriving safe and sound, she was reassured.",funFact:"French verbs change form for each person. The spoken forms are often simpler than the written ones."},
        {type:"teach",trg:"sans parler",src:"without speaking",pos:"verb",gender:null,phonetic:"son par-LEH",note:"Sans + infinitive = without doing.\nSans parler = without speaking, sans bouger = without moving.",example:"A: Comment s'est passé l'examen?\nB: J'ai attendu deux heures sans parler à personne.\nA: Tu étais nerveux?\nB: Oui, je suis resté assis sans bouger.",exampleSrc:"A: How did the exam go?\nB: I waited two hours without speaking to anyone.\nA: Were you nervous?\nB: Yes, I sat there without moving.",funFact:"A regular -er verb, the most common French verb group (~90% of all verbs)."},
        {type:"teach",trg:"avant de partir",src:"before leaving",pos:"verb",gender:null,phonetic:"ah-VON duh par-TEER",note:"Avant de + infinitive = before doing.\nThe infinitive is always the base form of the verb.",example:"A: Tu as tout préparé?\nB: Oui, avant de partir, j'ai vérifié ma valise.\nA: Tu n'oublies rien?\nB: Non, avant de partir je vérifie toujours deux fois.",exampleSrc:"A: Did you prepare everything?\nB: Yes, before leaving, I checked my suitcase.\nA: You're not forgetting anything?\nB: No, before leaving I always check twice.",funFact:"A -ir verb. Many follow the -ir pattern with -iss- in plural forms."},
        {type:"tip",title:"Three Key Constructions",deepDive:"Après requires the compound infinitive (avoir/être + past participle) because the action is completed. Sans and avant de use the simple infinitive because the action has not occurred yet or is simultaneous. Compare: Après avoir mangé (after eating, done), Avant de manger (before eating, not yet done).",text:"1. APRÈS + avoir/être + past participle\n   = after doing (completed action)\n   Après avoir fini, je suis parti.\n   Après être rentrée, elle a dîné.\n\n2. SANS + infinitive\n   = without doing\n   Il est parti sans dire au revoir.\n   Elle a accepté sans hésiter.\n\n3. AVANT DE + infinitive\n   = before doing\n   Avant de répondre, réfléchis bien.\n   Avant de partir, ferme la porte.\n\nAll three require the SAME subject for both actions."},
        {type:"mc",q:"'Après avoir étudié, il s'est couché.' What happened first?",opts:["He studied, then went to bed","He went to bed, then studied","Both happened at the same time","He studied instead of sleeping"],ans:"He studied, then went to bed",hint:"The après construction describes the action that was completed before the main verb."},
        {type:"fb",opts:["sans","avant","après","en"],hint:"The preposition meaning 'without' introduces an action that did NOT happen.",s:"Elle est partie {1} dire au revoir.",a:["sans"]},
        {type:"teach",trg:"après s'être réveillé",src:"after waking up",pos:"noun",gender:null,phonetic:"ah-PREH SETR reh-veh-YEH",note:"Reflexive: après + pronoun + être + past participle.\nAprès m'être réveillé (I), t'être levé (you), s'être habillé (he).",example:"A: Que fais-tu le matin?\nB: Après m'être réveillé, je prends une douche.\nA: Tu te lèves tôt?\nB: Oui, après m'être réveillé à six heures, je fais du sport.",exampleSrc:"A: What do you do in the morning?\nB: After waking up, I take a shower.\nA: Do you get up early?\nB: Yes, after waking up at six, I exercise.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"mc",q:"Complete: '_____ de manger, lave-toi les mains.'",opts:["Avant","Après","Sans","En"],ans:"Avant",hint:"The sequence requires washing hands to happen first, so the action of eating has not started yet."},
        {type:"fb",opts:["avoir","être","faire","en"],hint:"The compound infinitive for most verbs uses the auxiliary that pairs with a past participle.",s:"Après {1} fini ses devoirs, il a joué dehors.",a:["avoir"]},
        {type:"match",pairs:[{trg:"après avoir mangé",src:"after eating"},{trg:"sans hésiter",src:"without hesitating"},{trg:"avant de répondre",src:"before answering"},{trg:"après être parti",src:"after leaving"}]},
        {type:"mc",q:"Why does 'après être arrivée' have an extra -e?",opts:["The subject is feminine, so the participle agrees","All past participles end in -e","Arrivée is an irregular form","It is a spelling variation"],ans:"The subject is feminine, so the participle agrees",hint:"With être as auxiliary, the past ___ matches the ___ in gender and number."},
        {type:"drag_fill",hint:"He left the party without doing something: preposition plus infinitive.",s:"Il a quitté la fête {1} {2} au revoir à personne.",blanks:{"1":"sans","2":"dire"},pool:["sans","dire","avant","dit","de","en"]},
        {type:"fb",opts:["de","à","en","par"],hint:"The preposition that links avant to an infinitive is always the same small word.",s:"Avant {1} dormir, elle lit toujours un livre.",a:["de"]},
        {type:"mc",q:"Which is correct for 'After having finished the project'?",opts:["Après avoir terminé le projet","Après terminer le projet","Après en terminant le projet","Après de terminer le projet"],ans:"Après avoir terminé le projet",hint:"The compound infinitive requires an auxiliary between ___ and the participle."},
        {type:"drag_fill",hint:"After arriving home: the preposition for 'after' + the auxiliary for movement verbs. Slot 3 is empty.",s:"{1} {2} {3} rentrée, elle a préparé le dîner.",blanks:{"1":"Après","2":"être","3":""},pool:["Après","être","Avant","avoir","de","en"]},
        {type:"mc",q:"'Sans réfléchir, il a accepté.' What does sans express?",opts:["He accepted without thinking about it","He thought before accepting","He refused because he was thinking","He was thinking while accepting"],ans:"He accepted without thinking about it",hint:"The preposition sans indicates the absence of the action that follows."}
  ]},
  {id:"fre21l8",title:"Révision Complète",icon:"🎓",xp:15,board:true,steps:[
        {type:"intro",title:"Révision Complète",desc:"Review all gérondif constructions: simultaneous actions, manner, cause, tout en for contrast, verbal vs adjectival participles, and the advanced constructions après avoir, sans, avant de.",goals:["Distinguish all uses of the gérondif","Apply tout en for contrast","Choose the correct construction for context"]},
        {type:"mc",q:"Form the present participle of pouvoir (nous pouvons):",opts:["pouvant","pouvont","pouvoirant","poussant"],ans:"pouvant",hint:"Take the stem from the nous form and add the standard participle suffix."},
        {type:"fb",opts:["cherchant","chercher","cherché","cherche"],hint:"The gérondif requires the present participle form after en.",s:"Elle a trouvé la réponse en {1} attentivement.",a:["cherchant"]},
        {type:"mc",q:"'Il s'est blessé en jouant au football.' The gérondif expresses:",opts:["The cause/circumstance of the injury","How well he played","That he played after the injury","A contrast between playing and injury"],ans:"The cause/circumstance of the injury",hint:"The gérondif explains when and why the main event happened."},
        {type:"teach",trg:"En voyageant, on découvre de nouvelles cultures",src:"By traveling, you discover new cultures",pos:"intj",gender:null,phonetic:"on vwah-yah-ZHON on deh-KOOVR duh noo-VEL kool-TOOR",note:"En voyageant = by traveling (manner/means).\nA general truth about the benefits of travel.",example:"A: Pourquoi tu voyages autant?\nB: En voyageant, on découvre de nouvelles cultures.\nA: C'est vrai, on apprend beaucoup.\nB: Oui, en voyageant on comprend mieux le monde.",exampleSrc:"A: Why do you travel so much?\nB: By traveling, you discover new cultures.\nA: That's true, you learn a lot.\nB: Yes, by traveling you understand the world better.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"drag_fill",hint:"The gérondif describes the method. The third blank is empty here.",s:"{1} {2} {3} le livre, il a mieux compris la leçon.",blanks:{"1":"En","2":"relisant","3":""},pool:["En","relisant","Après","lire","relu","Tout"]},
        {type:"match",pairs:[
          {trg:"en mangeant",src:"while/by eating"},
          {trg:"tout en sachant",src:"despite knowing"},
          {trg:"après avoir mangé",src:"after eating"},
          {trg:"sans manger",src:"without eating"},
          {trg:"avant de manger",src:"before eating"}
        ]},
        {type:"mc",q:"'Des nouvelles choquantes' vs 'des nouvelles choquant l'opinion'. In which does the participle agree?",opts:["Des nouvelles choquantes (adjective)","Des nouvelles choquant l'opinion (verbal)","Both agree","Neither agrees"],ans:"Des nouvelles choquantes (adjective)",hint:"The version with a complement describes an action, while the version without describes a quality."},
        {type:"fb",opts:["étant","être","été","est"],hint:"The irregular participle of être follows tout en for concession.",s:"Tout en {1} d'accord, je préfère une autre solution.",a:["étant"]},
        {type:"mc",q:"Complete: 'Après _____ ses valises, elle est partie à l'aéroport.'",opts:["avoir fait","faire","en faisant","faisant"],ans:"avoir fait",hint:"The compound infinitive follows après for a completed action before the main event."},
        {type:"drag_fill",hint:"He went out without doing something: preposition plus infinitive base form.",s:"Il est sorti {1} {2} son parapluie.",blanks:{"1":"sans","2":"prendre"},pool:["sans","prendre","en","pris","avant","de"]},
        {type:"mc",q:"Which sentence uses tout en correctly for contrast?",opts:["Tout en comprenant le danger, il a plongé","En comprenant le danger, il a plongé","Tout comprenant le danger, il a plongé","Tout en comprend le danger, il a plongé"],ans:"Tout en comprenant le danger, il a plongé",hint:"The full construction needs the invariable word plus en plus the participle form."},
        {type:"fb",opts:["de","en","à","par"],hint:"The linking word between avant and an infinitive is always the same.",s:"Avant {1} répondre, lisez bien la question.",a:["de"]},
        {type:"teach",trg:"Tout en reconnaissant ses qualités, je trouve qu'il manque d'expérience",src:"While acknowledging his qualities, I find he lacks experience",pos:"intj",gender:null,phonetic:"too ton ruh-ko-neh-SON seh kah-lee-TEH zhuh TROOV keel MONK deks-peh-RYONS",note:"Tout en + gérondif for nuanced concession.\nCommon in professional and diplomatic language.",example:"A: Que penses-tu du candidat?\nB: Tout en reconnaissant ses qualités, je trouve qu'il manque d'expérience.\nA: Tu préfères l'autre candidat?\nB: Oui, tout en appréciant celui-ci, l'autre est plus qualifié.",exampleSrc:"A: What do you think of the candidate?\nB: While acknowledging his qualities, I find he lacks experience.\nA: Do you prefer the other candidate?\nB: Yes, while appreciating this one, the other is more qualified.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"mc",q:"'En arrivant au bureau, j'ai remarqué un colis.' The gérondif here is:",opts:["Simultaneous/temporal (when arriving)","Manner (how I arrived)","Contrast (despite arriving)","Cause (arriving made me notice)"],ans:"Simultaneous/temporal (when arriving)",hint:"The gérondif describes what was happening at the moment of the main action."},
        {type:"drag_fill",hint:"The compound infinitive describes the action completed before the main clause.",s:"{1} {2} {3} le dîner, nous avons regardé un film.",blanks:{"1":"Après","2":"avoir","3":"préparé"},pool:["Après","avoir","préparé","En","préparant","de"]},
        {type:"fb",opts:["sans","en","avant","après"],hint:"The preposition expressing the absence of hesitation comes before the infinitive.",s:"Il a répondu {1} hésiter une seconde.",a:["sans"]},
        {type:"mc",q:"Which is the correct gérondif of avoir?",opts:["en ayant","en avant","en avont","en eu"],ans:"en ayant",hint:"This verb has an irregular present participle that does not follow the nous stem."},
        {type:"drag_fill",hint:"Before doing something: two small words introduce the infinitive.",s:"{1} {2} partir, n'oublie pas tes clés.",blanks:{"1":"Avant","2":"de"},pool:["Avant","de","En","Après","avoir","sans"]},
        {type:"mc",q:"'Les résultats étonnants de cette étude.' Is étonnants verbal or adjectival?",opts:["Adjectival (agrees with les résultats, describes quality)","Verbal (describes an action in progress)","Both meanings apply equally","Neither, it is a noun"],ans:"Adjectival (agrees with les résultats, describes quality)",hint:"Without an object or complement, and with agreement, the participle functions as a descriptor."}
  ]},
  {id:"fre21l8b",title:"Les Médias et l'Actualité",icon:"📰",xp:20,board:true,steps:[
        {type:"intro",title:"Media & News Vocabulary",desc:"Les mots pour parler des médias et de l'actualité.\nLearn vocabulary for discussing news and media in French.",goals:["Learn 12 media vocabulary words","Discuss news topics in French","Express opinions about media"]},
        {type:"teach",trg:"l'article",src:"the article",pos:"noun",gender:"m",note:"l'article (m.)\nécrire un article (to write an article).\nAlso: un article de presse (press article).",example:"A: Tu as lu cet article dans le journal ?\nB: Oui, c'est très intéressant.\nA: De quoi ça parle ?\nB: Du changement climatique en Europe.",exampleSrc:"A: Did you read this article in the newspaper?\nB: Yes, it's very interesting.\nA: What is it about?\nB: About climate change in Europe.",funFact:"Cognate with English 'article'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"le/la journaliste",src:"the journalist",pos:"intj",gender:null,note:"le journaliste (m.), la journaliste (f.)\nSame spelling, article changes.",example:"A: Ton frère est journaliste, non ?\nB: Oui, il travaille pour un quotidien.\nA: Il écrit sur quoi ?\nB: Sur la politique internationale.",exampleSrc:"A: Your brother is a journalist, right?\nB: Yes, he works for a daily paper.\nA: What does he write about?\nB: About international politics.",funFact:"French gave English roughly 30% of its vocabulary. Many formal English words have French origins."},
        {type:"teach",trg:"l'émission",src:"the broadcast / TV show",pos:"noun",gender:"m",note:"l'émission (f.)\nune émission de radio (radio show).\nune émission de télévision (TV show).",example:"A: Tu regardes quelle émission ce soir ?\nB: Un documentaire sur la nature.\nA: Sur quelle chaîne ?\nB: Sur France 2, à 21 heures.",exampleSrc:"A: What show are you watching tonight?\nB: A nature documentary.\nA: On which channel?\nB: On France 2, at 9 PM.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"les informations",src:"the news",pos:"noun",gender:"pl",note:"les informations (f. pl.)\nShort form: les infos.\nAlso: les nouvelles (the news).",example:"A: Tu as regardé les informations ce matin ?\nB: Non, qu'est-ce qui s'est passé ?\nA: Il y a eu un tremblement de terre.\nB: C'est terrible ! Où exactement ?",exampleSrc:"A: Did you watch the news this morning?\nB: No, what happened?\nA: There was an earthquake.\nB: That's terrible! Where exactly?",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"l'internet",src:"the internet",pos:"noun",gender:"m",note:"l'internet (m.)\nsur internet (on the internet).\nAlso: le site web, le site internet.",example:"A: Tu as cherché sur internet ?\nB: Oui, j'ai trouvé beaucoup d'informations.\nA: Sur quel site ?\nB: Sur plusieurs sites différents.",exampleSrc:"A: Did you search on the internet?\nB: Yes, I found a lot of information.\nA: On which website?\nB: On several different websites.",funFact:"Cognate with English 'internet'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"les réseaux sociaux",src:"social media",pos:"noun",gender:"pl",note:"les réseaux sociaux (m. pl.)\nun réseau social (a social network).\npublier (to publish, to post).",example:"A: Tu es sur les réseaux sociaux ?\nB: Oui, j'utilise Instagram et LinkedIn.\nA: Tu postes souvent ?\nB: Non, je regarde surtout ce que les autres publient.",exampleSrc:"A: Are you on social media?\nB: Yes, I use Instagram and LinkedIn.\nA: Do you post often?\nB: No, I mostly look at what others publish.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"la publicité",src:"the advertisement",pos:"noun",gender:"f",note:"la publicité (f.)\nShort form: la pub.\nune publicité = an ad.\nla publicité = advertising (general).",example:"A: Il y a trop de publicité à la télé.\nB: C'est vrai, c'est agaçant.\nA: Tu utilises un bloqueur de publicité en ligne ?\nB: Oui, pour les sites internet.",exampleSrc:"A: There's too much advertising on TV.\nB: It's true, it's annoying.\nA: Do you use an ad blocker online?\nB: Yes, for websites.",funFact:"Feminine noun. Words ending in -tion, -sion, -ure are usually feminine."},
        {type:"teach",trg:"l'opinion",src:"the opinion",pos:"noun",gender:"m",note:"l'opinion (f.)\nAlso: l'avis (m.) (opinion, view).\nà mon avis (in my opinion).",example:"A: Quelle est ton opinion sur ce sujet ?\nB: Je pense que c'est compliqué.\nA: Tu es pour ou contre ?\nB: Je suis plutôt pour, mais avec des réserves.",exampleSrc:"A: What is your opinion on this topic?\nB: I think it's complicated.\nA: Are you for or against?\nB: I'm rather for it, but with reservations.",funFact:"Cognate with English 'opinion'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"l'événement",src:"the event",pos:"noun",gender:"m",note:"l'événement (m.)\nAlso spelled: l'évènement.\nun événement sportif (sporting event).",example:"A: C'est un événement important pour la ville.\nB: Oui, tout le monde en parle.\nA: Tu vas y assister ?\nB: Bien sûr, je ne veux pas le manquer.",exampleSrc:"A: It's an important event for the city.\nB: Yes, everyone is talking about it.\nA: Are you going to attend?\nB: Of course, I don't want to miss it.",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"teach",trg:"le journal",src:"the newspaper",pos:"noun",gender:"m",note:"le journal (m.)\nPlural: les journaux.\nAlso: le quotidien (daily paper).",example:"A: Tu lis encore le journal papier ?\nB: Non, je lis les nouvelles en ligne.\nA: Quel site préfères-tu ?\nB: Le Monde, c'est assez complet.",exampleSrc:"A: Do you still read the paper newspaper?\nB: No, I read the news online.\nA: Which website do you prefer?\nB: Le Monde, it's quite comprehensive.",funFact:"Masculine noun. Words ending in -age, -ment, -isme are usually masculine."},
        {type:"teach",trg:"la vidéo",src:"the video",pos:"noun",gender:"f",note:"la vidéo (f.)\nregarder une vidéo (to watch a video).\npartager (to share).",example:"A: Tu as vu cette vidéo en ligne ?\nB: Laquelle ?\nA: Celle sur les nouvelles technologies.\nB: Ah oui, je l'ai partagée avec mes amis.",exampleSrc:"A: Did you see this video online?\nB: Which one?\nA: The one about new technologies.\nB: Oh yes, I shared it with my friends.",funFact:"Cognate with English 'video'. Many English words were borrowed from French after 1066."},
        {type:"teach",trg:"l'information",src:"the information / the piece of news",pos:"noun",gender:"m",note:"l'information (f.)\nSingular = a piece of news.\nPlural (les informations) = the news.",example:"A: J'ai une information importante.\nB: Qu'est-ce que c'est ?\nA: L'entreprise va embaucher 50 personnes.\nB: C'est une bonne nouvelle !",exampleSrc:"A: I have some important information.\nB: What is it?\nA: The company is going to hire 50 people.\nB: That's good news!",funFact:"French nouns are either masculine or feminine. The article gives it away."},
        {type:"tip",title:"Talking About News in French",deepDive:"French distinguishes:\nles informations = TV/radio news broadcast\nles nouvelles = news in general\nl'actualité = current events, current affairs\n\nTu suis l'actualité ? (Do you follow current events?)",text:"Useful phrases for discussing the news:\n\nSelon l'article... (According to the article...)\nD'après le journal... (According to the newspaper...)\nJ'ai entendu dire que... (I heard that...)\nIl paraît que... (It seems that...)"},
        {type:"mc",q:"Which word means 'the journalist' in French?",opts:["le/la journaliste","le journal","l'article","l'émission"],ans:"le/la journaliste",hint:"The person who writes articles and reports news stories."},
        {type:"mc",q:"'Les réseaux sociaux' means:",opts:["social media","social events","TV networks","news channels"],ans:"social media",hint:"Platforms like Instagram and LinkedIn where people connect online."},
        {type:"fb",opts:["article","événement","journal","opinion"],hint:"A written text published in a newspaper or magazine.",s:"J'ai lu un {1} très intéressant dans le journal.",a:["article"]},
        {type:"fb",opts:["publicité","information","vidéo","opinion"],hint:"Commercial messages that try to sell you products.",s:"Il y a trop de {1} entre les émissions de télévision.",a:["publicité"]},
        {type:"mc",q:"What does 'l'émission' mean?",opts:["the broadcast / TV show","the newspaper","the event","the opinion"],ans:"the broadcast / TV show",hint:"A program you watch on TV or listen to on the radio."},
        {type:"match",pairs:[{trg:"le journal",src:"the newspaper"},{trg:"l'opinion",src:"the opinion"},{trg:"la vidéo",src:"the video"},{trg:"l'événement",src:"the event"},{trg:"les informations",src:"the news"}]},
        {type:"fb",opts:["informations","publicités","articles","opinions"],hint:"The daily TV news program that reports current events.",s:"Tu as regardé les {1} ce soir ? Il y a eu un accident.",a:["informations"]},
        {type:"drag_fill",hint:"The reporter wrote a text about something that happened.",s:"Le {1} a écrit un {2} sur l'{3} de ce week-end.",blanks:{"1":"journaliste","2":"article","3":"événement"},pool:["journaliste","article","événement","publicité"]}
  ]}
]};
